      dotenv.env['AWS_ACCESS_KEY_ID'] ?? '';

  static String get awsSecretAccessKey =>
      dotenv.env['AWS_SECRET_ACCESS_KEY'] ?? '';

  static String get awsRegion =>
      dotenv.env['AWS_REGION'] ?? 'us-east-1';

  static String get awsS3Bucket =>
      dotenv.env['AWS_S3_BUCKET'] ?? '';

  static String get googleCloudApiKey =>
      dotenv.env['GOOGLE_CLOUD_API_KEY'] ?? '';

  static Future<void> load() async {
    await dotenv.load(fileName: '.env');
