}

// lib/services/s3_upload_service.dart
import 'dart:convert';
import 'dart:io';
import 'dart:typed_data';
import 'package:crypto/crypto.dart' as crypto_lib;
import 'package:http/http.dart' as http;
import 'package:path/path.dart' as path_lib;
import 'package:uuid/uuid.dart';
import '../config/env_config.dart';

class HmacSha256 {
  static List<int> sign(List<int> key, List<int> message) {
    final hmac = crypto_lib.Hmac(crypto_lib.sha256, key);
    return hmac.convert(message).bytes;
  }
}

class S3UploadService {
  static final Uuid _uuid = const Uuid();

  static Future<S3UploadResult> uploadFile(File file) async {
    final String fileName =
        '${_uuid.v4()}${path_lib.extension(file.path)}';
    final String objectKey = 'uploads/$fileName';
    final Uint8List fileBytes = await file.readAsBytes();
    final String contentType = _getContentType(file.path);

    final String bucket = EnvConfig.awsS3Bucket;
    final String region = EnvConfig.awsRegion;
    final String host = '$bucket.s3.$region.amazonaws.com';
    final String url = 'https://$host/$objectKey';

    final DateTime now = DateTime.now().toUtc();
    final String dateStamp = _formatDate(now);
    final String amzDate = _formatAmzDate(now);

    final String payloadHash =
        crypto_lib.sha256.convert(fileBytes).toString();

    final Map<String, String> headers = {
      'Host': host,
      'x-amz-date': amzDate,
      'x-amz-content-sha256': payloadHash,
      'Content-Type': contentType,
    };

    final String signedHeaders = (headers.keys.toList()
          ..sort((a, b) => a.toLowerCase().compareTo(b.toLowerCase())))
        .map((h) => h.toLowerCase())
        .join(';');

    final String canonicalHeaders = (headers.keys.toList()
          ..sort((a, b) => a.toLowerCase().compareTo(b.toLowerCase())))
        .map((h) => '${h.toLowerCase()}:${headers[h]!.trim()}')
        .join('\n');

    final String canonicalRequest = [
      'PUT',
      '/$objectKey',
      '',
      '$canonicalHeaders\n',
      signedHeaders,
      payloadHash,
    ].join('\n');

    final String credentialScope =
        '$dateStamp/$region/s3/aws4_request';

    final String stringToSign = [
      'AWS4-HMAC-SHA256',
      amzDate,
      credentialScope,
      crypto_lib.sha256.convert(utf8.encode(canonicalRequest)).toString(),
    ].join('\n');

    final List<int> signingKey = _getSignatureKey(
      EnvConfig.awsSecretAccessKey,
      dateStamp,
      region,
      's3',
    );

    final String signature = HmacSha256.sign(
      signingKey,
      utf8.encode(stringToSign),
    ).map((b) => b.toRadixString(16).padLeft(2, '0')).join();

    final String authorization =
        'AWS4-HMAC-SHA256 Credential=${EnvConfig.awsAccessKeyId}/$credentialScope, '
        'SignedHeaders=$signedHeaders, Signature=$signature';

    headers['Authorization'] = authorization;

    try {
      final response = await http.put(
        Uri.parse(url),
        headers: headers,
        body: fileBytes,
      );

      if (response.statusCode == 200 || response.statusCode == 201) {
        return S3UploadResult(
          success: true,
          url: url,
          objectKey: objectKey,
        );
      } else {
        return S3UploadResult(
          success: false,
          error: 'Upload failed: ${response.statusCode} - ${response.body}',
        );
      }
    } catch (e) {
      return S3UploadResult(
        success: false,
        error: 'Upload error: $e',
      );
    }
  }

  static List<int> _getSignatureKey(
    String key,
    String dateStamp,
    String regionName,
    String serviceName,
  ) {
    final kDate =
        HmacSha256.sign(utf8.encode('AWS4$key'), utf8.encode(dateStamp));
    final kRegion = HmacSha256.sign(kDate, utf8.encode(regionName));
    final kService = HmacSha256.sign(kRegion, utf8.encode(serviceName));
    final kSigning =
        HmacSha256.sign(kService, utf8.encode('aws4_request'));
    return kSigning;
  }

  static String _formatDate(DateTime dt) =>
      '${dt.year}${dt.month.toString().padLeft(2, '0')}${dt.day.toString().padLeft(2, '0')}';

  static String _formatAmzDate(DateTime dt) =>
      '${_formatDate(dt)}T${dt.hour.toString().padLeft(2, '0')}${dt.minute.toString().padLeft(2, '0')}${dt.second.toString().padLeft(2, '0')}Z';

  static String _getContentType(String filePath) {
    final ext = path_lib.extension(filePath).toLowerCase();
    switch (ext) {
      case '.jpg':
      case '.jpeg':
        return 'image/jpeg';
      case '.png':
        return 'image/png';
      case '.gif':
        return 'image/gif';
      case '.webp':
        return 'image/webp';
      default:
        return 'application/octet-stream';
    }
  }
}

class S3UploadResult {
  final bool success;
  final String? url;
  final String? objectKey;
  final String? error;

  S3UploadResult({
    required this.success,
    this.url,
    this.objectKey,
    this.error,
  });
}

// lib/services/vision_service.dart
import 'dart:convert';
import 'dart:io';
import 'package:http/http.dart' as http;
import '../config/env_config.dart';

class VisionAnalysisResult {
  final List<LabelAnnotation> labels;
  final List<FaceAnnotation> faces;
  final List<TextAnnotation> texts;
  final List<ObjectAnnotation> objects;
  final SafeSearchAnnotation? safeSearch;
  final List<ColorInfo> dominantColors;
  final List<WebEntity> webEntities;
  final String? error;

  VisionAnalysisResult({
    this.labels = const [],
    this.faces = const [],
    this.texts = const [],
    this.objects = const [],
    this.safeSearch,
    this.dominantColors = const [],
    this.webEntities = const [],
    this.error,
  });

  bool get hasError => error != null;
  bool get isEmpty =>
      labels.isEmpty &&
      faces.isEmpty &&
      texts.isEmpty &&
      objects.isEmpty;
}

class LabelAnnotation {
  final String description;
  final double score;

  LabelAnnotation({required this.description, required this.score});
}

class FaceAnnotation {
  final String joyLikelihood;
  final String sorrowLikelihood;
  final String angerLikelihood;
  final String surpriseLikelihood;
  final double detectionConfidence;

  FaceAnnotation({
    required this.joyLikelihood,
    required this.sorrowLikelihood,
    required this.angerLikelihood,
    required this.surpriseLikelihood,
    required this.detectionConfidence,
  });

  String get dominantEmotion {
    final emotions = {
      'Joy': _likelihoodScore(joyLikelihood),
      'Sorrow': _likelihoodScore(sorrowLikelihood),
      'Anger': _likelihoodScore(angerLikelihood),
      'Surprise': _likelihoodScore(surpriseLikelihood),
    };
    final sorted = emotions.entries.toList()
      ..sort((a, b) => b.value.compareTo(a.value));
    return sorted.first.value > 0 ? sorted.first.key : 'Neutral';
  }

  int _likelihoodScore(String likelihood) {
    switch (likelihood) {
      case 'VERY_LIKELY':
        return 5;
      case 'LIKELY':
        return 4;
      case 'POSSIBLE':
        return 3;
      case 'UNLIKELY':
        return 2;
      case 'VERY_UNLIKELY':
        return 1;
      default:
        return 0;
    }
  }
}

class TextAnnotation {
  final String description;
  final String locale;

  TextAnnotation({required this.description, this.locale = ''});
}

class ObjectAnnotation {
  final String name;
  final double score;

  ObjectAnnotation({required this.name, required this.score});
}

class SafeSearchAnnotation {
  final String adult;
  final String violence;
  final String racy;
  final String spoof;
  final String medical;

  SafeSearchAnnotation({
    required this.adult,
    required this.violence,
    required this.racy,
    required this.spoof,
    required this.medical,
  });

  bool get isSafe =>
      adult != 'LIKELY' &&
      adult != 'VERY_LIKELY' &&
      violence != 'LIKELY' &&
      violence != 'VERY_LIKELY';
}

class ColorInfo {
  final int red;
  final int green;
  final int blue;
  final double score;
  final double pixelFraction;

  ColorInfo({
    required this.red,
    required this.green,
    required this.blue,
    required this.score,
    required this.pixelFraction,
  });
}

class WebEntity {
  final String description;
  final double score;

  WebEntity({required this.description, required this.score});
}

class VisionService {
  static const String _baseUrl =
      'https://vision.googleapis.com/v1/images:annotate';

  static Future<VisionAnalysisResult> analyzeImage(File imageFile) async {
    try {
      final bytes = await imageFile.readAsBytes();
      final base64Image = base64Encode(bytes);

      final requestBody = {
        'requests': [
          {
            'image': {'content': base64Image},
            'features': [
              {'type': 'LABEL_DETECTION', 'maxResults': 15},
              {'type': 'FACE_DETECTION', 'maxResults': 10},
              {'type': 'TEXT_DETECTION', 'maxResults': 10},
              {'type': 'OBJECT_LOCALIZATION', 'maxResults': 15},
              {'type': 'SAFE_SEARCH_DETECTION'},
              {'type': 'IMAGE_PROPERTIES'},
              {'type': 'WEB_DETECTION', 'maxResults': 10},
            ],
          }
        ],
      };

      final response = await http.post(
        Uri.parse('$_baseUrl?key=${EnvConfig.googleCloudApiKey}'),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode(requestBody),
      );

      if (response.statusCode != 200) {
        return VisionAnalysisResult(
          error:
              'Vision API error: ${response.statusCode} - ${response.body}',
        );
      }

      final data = jsonDecode(response.body);
      final responseData = data['responses'][0] as Map<String, dynamic>;

      if (responseData.containsKey('error')) {
        return VisionAnalysisResult(
          error: responseData['error']['message'],
        );
      }

      return _parseResponse(responseData);
    } catch (e) {
      return VisionAnalysisResult(error: 'Analysis error: $e');
    }
  }

  static VisionAnalysisResult _parseResponse(Map<String, dynamic> data) {
    final labels = (data['labelAnnotations'] as List<dynamic>?)
            ?.map((l) => LabelAnnotation(
                  description: l['description'] ?? '',
                  score: (l['score'] ?? 0).toDouble(),
                ))
            .toList() ??
        [];

    final faces = (data['faceAnnotations'] as List<dynamic>?)
            ?.map((f) => FaceAnnotation(
                  joyLikelihood: f['joyLikelihood'] ?? 'UNKNOWN',
                  sorrowLikelihood: f['sorrowLikelihood'] ?? 'UNKNOWN',
                  angerLikelihood: f['angerLikelihood'] ?? 'UNKNOWN',
                  surpriseLikelihood:
                      f['surpriseLikelihood'] ?? 'UNKNOWN',
                  detectionConfidence:
                      (f['detectionConfidence'] ?? 0).toDouble(),
                ))
            .toList() ??
        [];

    final textAnnotations =
        data['textAnnotations'] as List<dynamic>? ?? [];
    final texts = textAnnotations.isNotEmpty
        ? [
            TextAnnotation(
              description: textAnnotations[0]['description'] ?? '',
              locale: textAnnotations[0]['locale'] ?? '',
            )
          ]
        : <TextAnnotation>[];

    final objects =
        (data['localizedObjectAnnotations'] as List<dynamic>?)
                ?.map((o) => ObjectAnnotation(
                      name: o['name'] ?? '',
                      score: (o['score'] ?? 0).toDouble(),
                    ))
                .toList() ??
            [];

    SafeSearchAnnotation? safeSearch;
    if (data['safeSearchAnnotation'] != null) {
      final ss = data['safeSearchAnnotation'];
      safeSearch = SafeSearchAnnotation(
        adult: ss['adult'] ?? 'UNKNOWN',
        violence: ss['violence'] ?? 'UNKNOWN',
        racy: ss['racy'] ?? 'UNKNOWN',
        spoof: ss['spoof'] ?? 'UNKNOWN',
        medical: ss['medical'] ?? 'UNKNOWN',
      );
    }

    List<ColorInfo> colors = [];
    if (data['imagePropertiesAnnotation'] != null) {
      final colorData = data['imagePropertiesAnnotation']
          ['dominantColors']?['colors'] as List<dynamic>?;
      colors = colorData
              ?.take(6)
              .map((c) {
                final color = c['color'] ?? {};
                return ColorInfo(
                  red: (color['red'] ?? 0).toInt(),
                  green: (color['green'] ?? 0).toInt(),
                  blue: (color['blue'] ?? 0).toInt(),
                  score: (c['score'] ?? 0).toDouble(),
                  pixelFraction: (c['pixelFraction'] ?? 0).toDouble(),
                );
              })
              .toList() ??
          [];
    }

    List<WebEntity> webEntities = [];
    if (data['webDetection'] != null) {
      webEntities = (data['webDetection']['webEntities']
                  as List<dynamic>?)
              ?.where((w) =>
                  w['description'] != null &&
                  (w['description'] as String).isNotEmpty)
              .map((w) => WebEntity(
                    description: w['description'] ?? '',
                    score: (w['score'] ?? 0).toDouble(),
                  ))
              .toList() ??
          [];
    }

    return VisionAnalysisResult(
      labels: labels,
      faces: faces,
      texts: texts,
      objects: objects,
      safeSearch: safeSearch,
      dominantColors: colors,
      webEntities: webEntities,
    );
  }
}

// lib/models/photo_analysis.dart
import 'dart:io';
import '../services/vision_service.dart';

enum AnalysisState { idle, uploading, analyzing, complete, error }

class PhotoAnalysis {
  final File imageFile;
  final String? s3Url;
  final VisionAnalysisResult? analysisResult;
  final AnalysisState state;
  final String? errorMessage;
  final DateTime createdAt;

  PhotoAnalysis({
    required this.imageFile,
    this.s3Url,
    this.analysisResult,
    this.state = AnalysisState.idle,
    this.errorMessage,
    DateTime? createdAt,
  }) : createdAt = createdAt ?? DateTime.now();

  PhotoAnalysis copyWith({
    String? s3Url,
    VisionAnalysisResult? analysisResult,
    AnalysisState? state,
    String? errorMessage,
  }) {
    return PhotoAnalysis(
      imageFile: imageFile,
      s3Url: s3Url ?? this.s3Url,
      analysisResult: analysisResult ?? this.analysisResult,
      state: state ?? this.state,
      errorMessage: errorMessage ?? this.errorMessage,
      createdAt: createdAt,
    );
  }
}

