// lib/screens/home_screen.dart
import 'dart:io';
import 'package:flutter/material.dart';
import 'package:image_picker/image_picker.dart';
import '../config/env_config.dart';
import '../models/photo_analysis.dart';
import '../services/s3_upload_service.dart';
import '../services/vision_service.dart';
import '../widgets/analysis_card.dart';
import '../widgets/photo_card.dart';

class HomeScreen extends StatefulWidget {
  const HomeScreen({super.key});

  @override
  State<HomeScreen> createState() => _HomeScreenState();
}

class _HomeScreenState extends State<HomeScreen> {
  final ImagePicker _picker = ImagePicker();
  final List<PhotoAnalysis> _analyses = [];
  bool _isProcessing = false;

  @override
  void initState() {
    super.initState();
    if (!EnvConfig.isConfigured) {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        _showConfigError();
      });
    }
  }

  void _showConfigError() {
    showDialog(
      context: context,
      builder: (ctx) => AlertDialog(
        title: const Text('Configuration Missing'),
        content: const Text(
          'Please create a .env file in the project root with:\n\n'
          'AWS_ACCESS_KEY_ID=your_key\n'
          'AWS_SECRET_ACCESS_KEY=your_secret\n'
          'AWS_REGION=us-east-1\n'
          'AWS_S3_BUCKET=your_bucket\n'
          'GOOGLE_CLOUD_API_KEY=your_api_key',
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(ctx),
            child: const Text('OK'),
          ),
        ],
      ),
    );
  }

  Future<void> _pickAndAnalyze(ImageSource source) async {
    if (_isProcessing) return;

    try {
      final XFile? pickedFile = await _picker.pickImage(
        source: source,
        maxWidth: 2048,
        maxHeight: 2048,
        imageQuality: 85,
      );

      if (pickedFile == null) return;

      setState(() => _isProcessing = true);

      final file = File(pickedFile.path);
      var analysis = PhotoAnalysis(
        imageFile: file,
        state: AnalysisState.uploading,
      );

      setState(() => _analyses.insert(0, analysis));

      // Upload to S3
      final uploadResult = await S3UploadService.uploadFile(file);

      if (uploadResult.success) {
        analysis = analysis.copyWith(
          s3Url: uploadResult.url,
          state: AnalysisState.analyzing,
        );
        setState(() => _analyses[0] = analysis);
      } else {
        // Continue with analysis even if upload fails
        analysis = analysis.copyWith(
          state: AnalysisState.analyzing,
          errorMessage: 'Upload warning: ${uploadResult.error}',
        );
        setState(() => _analyses[0] = analysis);
      }

      // Analyze with Vision API
      final visionResult = await VisionService.analyzeImage(file);

      if (visionResult.hasError) {
        analysis = analysis.copyWith(
          state: AnalysisState.error,
          errorMessage: visionResult.error,
        );
      } else {
        analysis = analysis.copyWith(
          analysisResult: visionResult,
          state: AnalysisState.complete,
        );
      }

      setState(() {
        _analyses[0] = analysis;
        _isProcessing = false;
      });
    } catch (e) {
      setState(() {
        if (_analyses.isNotEmpty &&
            _analyses[0].state != AnalysisState.complete) {
          _analyses[0] = _analyses[0].copyWith(
            state: AnalysisState.error,
            errorMessage: e.toString(),
          );
        }
        _isProcessing = false;
      });
    }
  }

  void _removeAnalysis(int index) {
    setState(() => _analyses.removeAt(index));
  }

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);

    return Scaffold(
      appBar: AppBar(
        title: Row(
          children: [
            Icon(Icons.auto_awesome, color: theme.colorScheme.primary),
            const SizedBox(width: 8),
            const Text('Photo Analyzer'),
          ],
        ),
        actions: [
          if (_analyses.isNotEmpty)
            IconButton(
              icon: const Icon(Icons.delete_sweep),
              onPressed: () {
                showDialog(
                  context: context,
                  builder: (ctx) => AlertDialog(
                    title: const Text('Clear All'),
                    content: const Text(
                        'Remove all analyzed photos?'),
                    actions: [
                      TextButton(
                        onPressed: () => Navigator.pop(ctx),
                        child: const Text('Cancel'),
                      ),
                      FilledButton(
                        onPressed: () {
                          setState(() => _analyses.clear());
                          Navigator.pop(ctx);
                        },
                        child: const Text('Clear'),
                      ),
                    ],
                  ),
                );
              },
            ),
        ],
      ),
      body: _analyses.isEmpty ? _buildEmptyState(theme) : _buildList(),
      floatingActionButton: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          FloatingActionButton.small(
            heroTag: 'gallery',
            onPressed:
                _isProcessing ? null : () => _pickAndAnalyze(ImageSource.gallery),
            child: const Icon(Icons.photo_library),
          ),
          const SizedBox(height: 12),
          FloatingActionButton.extended(
            heroTag: 'camera',
            onPressed:
                _isProcessing ? null : () => _pickAndAnalyze(ImageSource.camera),
            icon: const Icon(Icons.camera_alt),
            label: const Text('Capture'),
          ),
        ],
      ),
    );
  }

  Widget _buildEmptyState(ThemeData theme) {
    return Center(
      child: Padding(
        padding: const EdgeInsets.all(32.0),
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Icon(
              Icons.add_a_photo_outlined,
              size: 80,
              color: theme.colorScheme.primary.withOpacity(0.5),
            ),
            const SizedBox(height: 24),
            Text(
              'Capture or Select a Photo',
              style: theme.textTheme.headlineSmall,
              textAlign: TextAlign.center,
            ),
            const SizedBox(height: 12),
            Text(
              'Upload to S3 and analyze with Google Cloud Vision AI',
              style: theme.textTheme.bodyLarge?.copyWith(
                color: theme.colorScheme.onSurfaceVariant,
              ),
              textAlign: TextAlign.center,
            ),
            const SizedBox(height: 32),
            if (!EnvConfig.isConfigured)
              Card(
                color: theme.colorScheme.errorContainer,
                child: Padding(
                  padding: const EdgeInsets.all(16),
                  child: Row(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      Icon(Icons.warning_amber,
                          color: theme.colorScheme.onErrorContainer),
                      const SizedBox(width: 12),
                      Flexible(
                        child: Text(
                          '.env file not configured',
                          style: TextStyle(
                            color: theme.colorScheme.onErrorContainer,
                          ),
                        ),
                      ),
                    ],
                  ),
                ),
              ),
          ],
        ),
      ),
    );
  }

  Widget _buildList() {
    return ListView.builder(
      padding: const EdgeInsets.fromLTRB(16, 8, 16, 100),
      itemCount: _analyses.length,
      itemBuilder: (context, index) {
        final analysis = _analyses[index];
        return Dismissible(
          key: ValueKey(analysis.createdAt),
          direction: DismissDirection.endToStart,
          background: Container(
            alignment: Alignment.centerRight,
            padding: const EdgeInsets.only(right: 20),
            margin: const EdgeInsets.only(bottom: 16),
            decoration: BoxDecoration(
              color: Theme.of(context).colorScheme.error,
              borderRadius: BorderRadius.circular(16),
            ),
            child: Icon(
              Icons.delete,
              color: Theme.of(context).colorScheme.onError,
            ),
          ),
          onDismissed: (_) => _removeAnalysis(index),
          child: Column(
            children: [
              PhotoCard(analysis: analysis),
              if (analysis.state == AnalysisState.complete &&
                  analysis.analysisResult != null)
                AnalysisCard(result: analysis.analysisResult!),
              if (analysis.state == AnalysisState.error)
                _buildErrorCard(analysis),
              const SizedBox(height: 16),
            ],
          ),
        );
      },
    );
  }

  Widget _buildErrorCard(PhotoAnalysis analysis) {
    final theme = Theme.of(context);
    return Card(
      color: theme.colorScheme.errorContainer,
      margin: const EdgeInsets.only(top: 8),
      child: Padding(
        padding: const EdgeInsets.all(16),
        child: Row(
          children: [
            Icon(Icons.error_outline,
                color: theme.colorScheme.onErrorContainer),
            const SizedBox(width: 12),
            Expanded(
              child: Text(
                analysis.errorMessage ?? 'Unknown error occurred',
                style: TextStyle(
                  color: theme.colorScheme.onErrorContainer,
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }
}

// lib/widgets/photo_card.dart
import 'package:flutter/material.dart';
import '../models/photo_analysis.dart';

class PhotoCard extends StatelessWidget {
  final PhotoAnalysis analysis;

  const PhotoCard({super.key, required this.analysis});

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);

    return Card(
      clipBehavior: Clip.antiAlias,
      elevation: 2,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          Stack(
            children: [
              Image.file(
                analysis.imageFile,
                height: 250,
                width: double.infinity,
                fit: BoxFit.cover,
              ),
              if (analysis.state == AnalysisState.uploading ||
                  analysis.state == AnalysisState.analyzing)
                Positioned.fill(
                  child: Container(
                    color: Colors.black38,
                    child: Center(
                      child: Column(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          const CircularProgressIndicator(
                            color: Colors.white,
                          ),
                          const SizedBox(height: 16),
                          Text(
                            analysis.state == AnalysisState.uploading
                                ? 'Uploading to S3...'
                                : 'Analyzing with Vision AI...',
                            style: const TextStyle(
                              color: Colors.white,
                              fontSize: 16,
                              fontWeight: FontWeight.w500,
                            ),
                          ),
                        ],
                      ),
                    ),
                  ),
                ),
              Positioned(
                top: 8,
                right: 8,
                child: _buildStatusChip(theme),
              ),
            ],
          ),
          if (analysis.s3Url != null)
            Padding(
              padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 8),
              child: Row(
                children: [
                  Icon(Icons.cloud_done,
                      size: 16, color: theme.colorScheme.primary),
                  const SizedBox(width: 6),
                  Expanded(
                    child: Text(
                      analysis.s3Url!,
                      style: theme.textTheme.bodySmall?.copyWith(
                        color: theme.colorScheme.primary,
                      ),
                      overflow: TextOverflow.ellipsis,
                    ),
                  ),
                ],
              ),
            ),
        ],
      ),
    );
  }

  Widget _buildStatusChip(ThemeData theme) {
    IconData icon;
    String label;
    Color bgColor;
    Color fgColor;

    switch (analysis.state) {
      case AnalysisState.uploading:
        icon = Icons.cloud_upload;
        label = 'Uploading';
        bgColor = Colors.orange;
        fgColor = Colors.white;
        break;
      case AnalysisState.analyzing:
        icon = Icons.psychology;
        label = 'Analyzing';
        bgColor = Colors.blue;
        fgColor = Colors.white;
        break;
      case AnalysisState.complete:
        icon = Icons.check_circle;
        label = 'Complete';
        bgColor = Colors.green;
        fgColor = Colors.white;
        break;
      case AnalysisState.error:
        icon = Icons.error;
        label = 'Error';
        bgColor = Colors.red;
        fgColor = Colors.white;
        break;
      default:
        icon = Icons.hourglass_empty;
        label = 'Pending';
        bgColor = Colors.grey;
        fgColor = Colors.white;
    }

    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 6),
      decoration: BoxDecoration(
        color: bgColor.withOpacity(0.9),
        borderRadius: BorderRadius.circular(20),
      ),
      child: Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          Icon(icon, size: 14, color: fgColor),
          const SizedBox(width: 4),
          Text(
            label,
            style: TextStyle(
              color: fgColor,
              fontSize: 12,
              fontWeight: FontWeight.w600,
            ),
          ),
        ],
      ),
    );
  }
}

// lib/widgets/analysis_card.dart
import 'package:flutter/material.dart';
import '../services/vision_service.dart';

class AnalysisCard extends StatelessWidget {
  final VisionAnalysisResult result;

  const AnalysisCard({super.key, required this.result});

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);

    return Card(
      margin: const EdgeInsets.only(top: 8),
      child: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              children: [
                Icon(Icons.auto_awesome,
                    color: theme.colorScheme.primary, size: 20),
                const SizedBox(width: 8),
                Text(
                  'Analysis Results',
                  style: theme.textTheme.titleMedium?.copyWith(
                    fontWeight: FontWeight.bold,
                  ),
                ),
              ],
            ),
            const Divider(height: 24),

            // Labels
            if (result.labels.isNotEmpty) ...[
              _buildSectionTitle(theme, Icons.label, 'Labels'),
              const SizedBox(height: 8),
              Wrap(
                spacing: 6,
                runSpacing: 6,
                children: result.labels.map((label) {
                  return Chip(
                    label: Text(
                      '${label.description} (${(label.score * 100).toInt()}%)',
                      style: const TextStyle(fontSize: 12),
                    ),
                    backgroundColor:
                        theme.colorScheme.primaryContainer.withOpacity(0.5),
                    visualDensity: VisualDensity.compact,
                    materialTapTargetSize: MaterialTapTargetSize.shrinkWrap,
                  );
                }).toList(),
              ),
              const SizedBox(height: 16),
            ],

            // Objects
            if (result.objects.isNotEmpty) ...[
              _buildSectionTitle(theme, Icons.category, 'Objects Detected'),
              const SizedBox(height: 8),
              ...result.objects.map((obj) => Padding(
                    padding: const EdgeInsets.only(bottom: 4),
                    child: Row(
                      children: [
                        Expanded(
                          child: Text(obj.name),
                        ),
                        SizedBox(
                          width: 120,
                          child: LinearProgressIndicator(
                            value: obj.score,
                            backgroundColor:
                                theme.colorScheme.surfaceContainerHighest,
                          ),
                        ),
                        const SizedBox(width: 8),
                        Text(
                          '${(obj.score * 100).toInt()}%',
                          style: theme.textTheme.bodySmall,
                        ),
                      ],
                    ),
                  )),
              const SizedBox(height: 16),
            ],

            // Faces
            if (result.faces.isNotEmpty) ...[
              _buildSectionTitle(theme, Icons.face, 'Faces'),
              const SizedBox(height: 8),
              ...result.faces.asMap().entries.map((entry) {
                final face = entry.value;
                return Card(
                  color: theme.colorScheme.surfaceContainerHighest
                      .withOpacity(0.5),
                  child: Padding(
                    padding: const EdgeInsets.all(12),
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Text(
                          'Face ${entry.key + 1}',
                          style: theme.textTheme.titleSmall,
                        ),
                        const SizedBox(height: 4),
                        Text(
                          'Dominant emotion: ${face.dominantEmotion}',
                        ),
                        Text(
                          'Confidence: ${(face.detectionConfidence * 100).toInt()}%',
                          style: theme.textTheme.bodySmall,
                        ),
                        const SizedBox(height: 4),
                        Wrap(
                          spacing: 8,
                          children: [
                            _emotionChip('😊 Joy', face.joyLikelihood),
                            _emotionChip(
                                '😢 Sorrow', face.sorrowLikelihood),
                            _emotionChip('😠 Anger', face.angerLikelihood),
                            _emotionChip(
                                '😲 Surprise', face.surpriseLikelihood),
                          ],
                        ),
                      ],
                    ),
                  ),
                );
              }),
              const SizedBox(height: 16),
            ],

            // Text
            if (result.texts.isNotEmpty) ...[
              _buildSectionTitle(theme, Icons.text_fields, 'Detected Text'),
              const SizedBox(height: 8),
              Container(
                width: double.infinity,
                padding: const EdgeInsets.all(12),
                decoration: BoxDecoration(
                  color: theme.colorScheme.surfaceContainerHighest
                      .withOpacity(0.5),
                  borderRadius: BorderRadius.circular(8),
                  border: Border.all(
                      color: theme.colorScheme.outline.withOpacity(0.3)),
                ),
                child: SelectableText(
                  result.texts.first.description,
                  style: theme.textTheme.bodyMedium?.copyWith(
                    fontFamily: 'monospace',
                  ),
                ),
              ),
              const SizedBox(height: 16),
            ],

            // Dominant Colors
            if (result.dominantColors.isNotEmpty) ...[
              _buildSectionTitle(theme, Icons.palette, 'Dominant Colors'),
              const SizedBox(height: 8),
              SizedBox(
                height: 50,
                child: Row(
                  children: result.dominantColors.map((color) {
                    return Expanded(
                      flex: (color.pixelFraction * 100).toInt().clamp(1, 100),
                      child: Tooltip(
                        message:
                            'RGB(${color.red}, ${color.green}, ${color.blue})\n'
                            '${(color.pixelFraction * 100).toStringAsFixed(1)}%',
                        child: Container(
                          decoration: BoxDecoration(
                            color: Color.fromRGBO(
                              color.red,
                              color.green,
                              color.blue,
                              1,
                            ),
                            borderRadius: BorderRadius.circular(4),
                          ),
                          margin: const EdgeInsets.symmetric(horizontal: 1),
                        ),
                      ),
                    );
                  }).toList(),
                ),
              ),
              const SizedBox(height: 16),
            ],

            // Web Entities
            if (result.webEntities.isNotEmpty) ...[
              _buildSectionTitle(theme, Icons.language, 'Web Matches'),
              const SizedBox(height: 8),
              Wrap(
                spacing: 6,
                runSpacing: 6,
                children: result.webEntities.take(8).map((entity) {
                  return Chip(
                    label: Text(
                      entity.description,
                      style: const TextStyle(fontSize: 12),
                    ),
                    avatar: Icon(Icons.tag,
                        size: 14, color: theme.colorScheme.secondary),
                    backgroundColor:
                        theme.colorScheme.secondaryContainer.withOpacity(0.5),
                    visualDensity: VisualDensity.compact,
                    materialTapTargetSize: MaterialTapTargetSize.shrinkWrap,
                  );
                }).toList(),
              ),
              const SizedBox(height: 16),
            ],

            // Safe Search
            if (result.safeSearch != null) ...[
              _buildSectionTitle(
                  theme, Icons.security, 'Content Safety'),
              const SizedBox(height: 8),
              Row(
                children: [
                  Icon(
                    result.safeSearch!.isSafe
                        ? Icons.verified_user
                        : Icons.warning,
                    color: result.safeSearch!.isSafe
                        ? Colors.green
                        : Colors.orange,
                    size: 20,
                  ),
                  const SizedBox(width: 8),
                  Text(
                    result.safeSearch!.isSafe
                        ? 'Content is safe'
                        : 'Content may contain sensitive material',
                  ),
                ],
              ),
            ],
          ],
        ),
      ),
    );
  }

  Widget _buildSectionTitle(ThemeData theme, IconData icon, String title) {
    return Row(
      children: [
        Icon(icon, size: 18, color: theme.colorScheme.secondary),
        const SizedBox(width: 6),
        Text(
          title,
          style: theme.textTheme.titleSmall?.copyWith(
            fontWeight: FontWeight.w600,
            color: theme.colorScheme.secondary,
          ),
        ),
      ],
    );
  }

  Widget _emotionChip(String label, String likelihood) {
    Color color;
    switch (likelihood) {
      case 'VERY_LIKELY':
        color = Colors.green;
        break;
      case 'LIKELY':
        color = Colors.lightGreen;
        break;
      case 'POSSIBLE':
        color = Colors.amber;
        break;
      case 'UNLIKELY':
        color = Colors.orange;
        break;
      default:
        color = Colors.grey;
    }

    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
      decoration: BoxDecoration(
        color: color.withOpacity(0.2),
        borderRadius: BorderRadius.circular(12),
        border: Border.all(color: color.withOpacity(0.5)),
      ),
      child: Text(
        '$label: ${likelihood.replaceAll('_', ' ')}',
        style: TextStyle(fontSize: 11, color: color.shade700),
      ),
    );
  }
}

// Also need to add crypto dependency - update pubspec.yaml to include:
// crypto: ^3.0.3

This approach is **equally fast to set up** (just paste your keys into `.env` instead of into `.dart` files) but keeps credentials out of source code and version control. The `.env` file is loaded at runtime via `flutter_dotenv`.

**Quick setup for the hackathon:**
1. Create the `.env` file with your real keys
2. Confirm `.env` is in `.gitignore`
3. Run `flutter pub get` and go

The S3 upload service implements AWS Signature V4 signing manually so no AWS CLI is needed. The Vision API uses a simple REST call with the API key as a query parameter. Both work immediately with just the `.env` file.